{"path": "/tmp/sv-5eb1b77d41124dd7a3dc92cb75a88ffe/RecipeShare/Services/RecipeService.cs", "file_text": "using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt", Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes over the base.\n4. Tear mozzarella and distribute evenly.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil." },
        new Recipe { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti\nGuanciale or pancetta\nEggs\nPecorino Romano\nBlack pepper", Steps = "1. Cook spaghetti in salted water until al dente.\n2. Crisp guanciale in a pan over medium heat.\n3. Whisk eggs with grated pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat and stir in egg mixture.\n6. Serve immediately with extra pecorino." },
        new Recipe { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nTomato sauce\nHeavy cream\nGarlic\nGinger", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or broil chicken until charred.\n3. Sauté garlic and ginger in oil.\n4. Add tomato sauce and spices, simmer 15 minutes.\n5. Add cream and cooked chicken.\n6. Simmer 10 minutes and serve with rice." },
        new Recipe { Id = 4, Title = "Vegetable Pad Thai", Category = "Asian", Ingredients = "Rice noodles\nTofu\nBean sprouts\nPeanuts\nLime\nTamarind paste\nFish sauce\nSugar\nGarlic\nEggs", Steps = "1. Soak rice noodles in warm water 30 minutes.\n2. Press and cube tofu, pan-fry until golden.\n3. Make sauce: combine tamarind, fish sauce, and sugar.\n4. Stir-fry garlic, add eggs, scramble.\n5. Add noodles and sauce, toss until coated.\n6. Top with peanuts, bean sprouts, and lime." },
        new Recipe { Id = 5, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa", Steps = "1. Brown ground beef over medium-high heat.\n2. Add taco seasoning and water, simmer 5 minutes.\n3. Warm tortillas in a dry skillet.\n4. Assemble tacos with beef, lettuce, tomato, cheese.\n5. Top with sour cream and salsa." },
        new Recipe { Id = 6, Title = "Guacamole", Category = "Mexican", Ingredients = "Avocados\nLime juice\nCilantro\nRed onion\nJalapeño\nTomato\nSalt", Steps = "1. Halve avocados and remove pits.\n2. Mash avocado to desired consistency.\n3. Dice onion, jalapeño, tomato, and cilantro.\n4. Mix everything together with lime juice.\n5. Season with salt to taste.\n6. Serve immediately with tortilla chips." },
        new Recipe { Id = 7, Title = "Miso Ramen", Category = "Asian", Ingredients = "Ramen noodles\nMiso paste\nChicken broth\nSoft-boiled egg\nGreen onions\nCorn\nNori\nChashu pork", Steps = "1. Bring chicken broth to a simmer.\n2. Whisk in miso paste until dissolved.\n3. Cook ramen noodles according to package.\n4. Prepare soft-boiled eggs (6.5 minutes).\n5. Assemble bowls: noodles, broth, toppings.\n6. Garnish with green onions and nori." },
        new Recipe { Id = 8, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract", Steps = "1. Preheat oven to 425°F.\n2. Melt chocolate and butter together.\n3. Whisk eggs and sugar until thick.\n4. Fold chocolate mixture into eggs.\n5. Add flour and vanilla, fold gently.\n6. Bake in greased ramekins 12-14 minutes.\n7. Invert onto plates and serve immediately." },
    };

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null && stars >= 1 && stars <= 5)
        {
            recipe.TotalRating += stars;
            recipe.RatingCount++;
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }
}
"}

