arguments.new_str:
@page "/"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>RecipeShare - Home</PageTitle>

<div class="container">
    <h1>🍳 Welcome to RecipeShare</h1>
    <p class="lead">Discover and share delicious recipes from around the world.</p>

    <h2>Browse by Category</h2>
    <div class="row">
        @foreach (var category in RecipeService.GetCategories())
        {
            <div class="col-md-3 mb-4">
                <div class="card h-100">
                    <div class="card-body text-center">
                        <h5 class="card-title">@GetCategoryEmoji(category) @category</h5>
                        <p class="card-text">@RecipeService.GetByCategory(category).Count recipes</p>
                        <a href="/recipes/@category" class="btn btn-primary">Browse</a>
                    </div>
                </div>
            </div>
        }
    </div>
</div>

@code {
    private string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🇮🇹",
        "Indian" => "🇮🇳",
        "Asian" => "🥢",
        "Mexican" => "🌮",
        "Desserts" => "🍰",
        _ => "🍽️"
    };
}

arguments.file_text:
@page "/recipes/{Category}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@Category Recipes - RecipeShare</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@Category</li>
        </ol>
    </nav>

    <h1>@Category Recipes</h1>

    @if (recipes.Count == 0)
    {
        <p>No recipes found in this category.</p>
    }
    else
    {
        <div class="row">
            @foreach (var recipe in recipes)
            {
                <div class="col-md-4 mb-4">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text text-muted">
                                @if (recipe.RatingCount > 0)
                                {
                                    <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</span>
                                }
                                else
                                {
                                    <span>No ratings yet</span>
                                }
                            </p>
                            <a href="/recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public string Category { get; set; } = string.Empty;

    private IReadOnlyList<RecipeShare.Models.Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(Category);
    }
}

@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

<div class="container">
    @if (recipe is null)
    {
        <p>Recipe not found.</p>
    }
    else
    {
        <nav aria-label="breadcrumb">
            <ol class="breadcrumb">
                <li class="breadcrumb-item"><a href="/">Home</a></li>
                <li class="breadcrumb-item"><a href="/recipes/@recipe.Category">@recipe.Category</a></li>
                <li class="breadcrumb-item active">@recipe.Title</li>
            </ol>
        </nav>

        <h1>@recipe.Title</h1>
        <p class="text-muted">Category: @recipe.Category</p>

        <StarRating RecipeId="recipe.Id" CurrentAverage="recipe.AverageRating" RatingCount="recipe.RatingCount" />

        <h3 class="mt-4">Ingredients</h3>
        <ul>
            @foreach (var ingredient in recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
            {
                <li>@ingredient</li>
            }
        </ul>

        <h3>Instructions</h3>
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <p>@step</p>
        }
    }
</div>

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeShare.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<div class="my-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= hoverStar ? "star-active" : (star <= selectedStar ? "star-selected" : ""))"
              @onmouseover="() => hoverStar = star"
              @onmouseout="() => hoverStar = 0"
              @onclick="() => Rate(star)"
              role="button">
            ★
        </span>
    }
    @if (submitted)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }
    <div class="text-muted small mt-1">
        @if (RatingCount > 0)
        {
            <span>Average: @CurrentAverage.ToString("F1") ⭐ (@RatingCount ratings)</span>
        }
        else
        {
            <span>Be the first to rate!</span>
        }
    </div>
</div>

<style>
    .star {
